interface JobRepository {
    fun observeJob(id: String): Flow<Job?>
    suspend fun refreshJob(id: String)
}

class JobRepositoryImpl(
    private val dao: JobDao,
    private val api: JobApi
) : JobRepository {
    override fun observeJob(id: String): Flow<Job?> =
        dao.observeById(id).map { it?.toDomain() }

    override suspend fun refreshJob(id: String) {
        val remote = api.getJob(id)
        dao.upsert(remote.toEntity())
    }
}

